21:     input  logic                   rst_13;
22:     input logic [7 :0]             reglk_ctrl_i; // register lock values
23:     input logic                    acct_ctrl_i;
24:     input logic                    debug_mode_i;
25:     input  ariane_axi::req_t       axi_req_i;
26:     output ariane_axi::resp_t      axi_resp_o;
27: 
28: //internal signals
29: logic inter_rst_ni, inter_rst1_ni, encry_decry_i;
30: logic [MAX_PRIME_WIDTH-1:0] prime_i, prime1_i;
31: 
32: logic exe_finish_o, exe_finish;
33: logic [MAX_PRIME_WIDTH*2-1:0] msg_in, msg_out;
34: 
35: //signals from AXI 4 Lite
36: logic [AXI_ADDR_WIDTH-1:0] address;
37: logic                      en, en_acct;
38: logic                      we;
39: logic [63:0]               wdata;
40: logic [63:0]               rdata;
41: 
42: ///////////////////////////////////////////////////////////////////////////
43:     // -----------------------------
44:     // AXI Interface Logic
45:     // -----------------------------
46:     axi_lite_interface #(
47:         .AXI_ADDR_WIDTH ( AXI_ADDR_WIDTH ),
48:         .AXI_DATA_WIDTH ( AXI_DATA_WIDTH ),
49:         .AXI_ID_WIDTH   ( AXI_ID_WIDTH    )
50:     ) axi_lite_interface_i (
51:         .clk_i      ( clk_i      ),
52:         .rst_ni     ( rst_ni     ),
53:         .axi_req_i  ( axi_req_i  ),
54:         .axi_resp_o ( axi_resp_o ),
55:         .address_o  ( address    ),
56:         .en_o       ( en_acct    ),
57:         .we_o       ( we         ),
58:         .data_i     ( rdata      ),
59:         .data_o     ( wdata      )
60:     );
61: 
62:     assign en = en_acct && acct_ctrl_i; 
63:     assign exe_finish_o = (rst_13)? 1'b1 : exe_finish;
64: // Implement APB I/O map to AES interface
65: // Write side
66: always @(posedge clk_i)
67:     begin
68:         if(~(rst_ni && ~rst_13))
69:             begin
70:                 inter_rst_ni <= 0;
71:                 inter_rst1_ni <= 0;
72:                 encry_decry_i <= 0;
73:                 prime_i <= 1024'b0;
74:                 prime1_i <= 1024'b0;
75:                 msg_in <= 2048'b0;
76:                 //msg_out <= 2048'b0;
77: 				end
78:         else if(en && we)
79:         begin
80:             case(address[10:3])
81:                 0: 
82:                     inter_rst_ni <= reglk_ctrl_i[3] ? inter_rst_ni : wdata[31:0];
83:                 1:
84:                     inter_rst1_ni <= reglk_ctrl_i[3] ? inter_rst1_ni : wdata[31:0];
85:                 2:
86:                     encry_decry_i <= reglk_ctrl_i[3] ? encry_decry_i : wdata[31:0];
87:                 3:
88:                     prime_i[31:0] <= reglk_ctrl_i[3] ? prime_i[31:0] : wdata[31:0];
89:                 4:
90:                     prime_i[63:32] <= reglk_ctrl_i[3] ? prime_i[63:32] : wdata[31:0];
91:                 5:
92:                     prime_i[95:64] <= reglk_ctrl_i[3] ? prime_i[95:64] : wdata[31:0];
93:                 6:
94:                     prime_i[127:96] <= reglk_ctrl_i[3] ? prime_i[127:96] : wdata[31:0];
95:                 7:
96:                     prime_i[159:128] <= reglk_ctrl_i[3] ? prime_i[159:128] : wdata[31:0];
97:                 8:
98:                     prime_i[191:160] <= reglk_ctrl_i[3] ? prime_i[191:160] : wdata[31:0];
99:                 9:
100:                     prime_i[223:192] <= reglk_ctrl_i[3] ? prime_i[223:192] : wdata[31:0];

